// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedDayIndex, setSelectedDayIndex] = useState<number>(0);
  const [showDetails, setShowDetails] = useState<boolean>(true);

  const normalizedCondition = useMemo(() => {
    return props.condition.toLowerCase();
  }, [props.condition]);

  const conditionIcon = useMemo(() => {
    if (normalizedCondition.includes('sun') || normalizedCondition.includes('clear')) return '☀️';
    if (normalizedCondition.includes('cloud') || normalizedCondition.includes('overcast')) return '☁️';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle')) return '🌧️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('sleet')) return '❄️';
    if (normalizedCondition.includes('wind')) return '💨';
    if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist') || normalizedCondition.includes('haze')) return '🌫️';
    return '🌤️';
  }, [normalizedCondition]);

  const safeForecast = useMemo(() => {
    return Array.isArray(props.forecast) ? props.forecast : [];
  }, [props.forecast]);

  useEffect(() => {
    if (selectedDayIndex > safeForecast.length - 1) {
      setSelectedDayIndex(0);
    }
  }, [safeForecast.length, selectedDayIndex]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="lg"
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Current Weather</Text>
                <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              </Stack>
              <Text
                as={Clickable}
                onClick={() => setShowDetails(!showDetails)}
                color="var(--ggui-color-primary-600)"
                variant="label"
              >
                {showDetails ? 'Hide details' : 'Show details'}
              </Text>
            </Row>

            <Row justify="between" align="center" wrap>
              <Row align="center" gap="var(--ggui-spacing-3)">
                <Icon name={conditionIcon} size={40} color="var(--ggui-color-primary-600)" />
                <Stack gap="var(--ggui-spacing-1)">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {props.temperature}°{props.unit}
                  </Text>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
                </Stack>
              </Row>

              {showDetails && (
                <Row gap="var(--ggui-spacing-6)" wrap>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} {props.unit === 'C' ? 'km/h' : 'mph'}</Text>
                  </Stack>
                </Row>
              )}
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Divider margin="var(--ggui-spacing-1)" color="var(--ggui-color-outlineVariant)" />

            {safeForecast.length === 0 ? (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap>
                {safeForecast.map((item, index) => (
                  <Box
                    key={`${item.day || 'day'}-${index}`}
                    as={Clickable}
                    onClick={() => setSelectedDayIndex(index)}
                    padding="var(--ggui-spacing-3)"
                    background={selectedDayIndex === index ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Stack align="center" gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurface)">{item.day || 'Day'}</Text>
                      <Icon name={item.icon || '🌤️'} size={22} color="var(--ggui-color-primary-600)" />
                      <Text variant="caption" color="var(--ggui-color-onSurface)">
                        {typeof item.high === 'number' ? item.high : '--'}° / {typeof item.low === 'number' ? item.low : '--'}°
                      </Text>
                    </Stack>
                  </Box>
                ))}
              </Row>
            )}

            {safeForecast[selectedDayIndex] && (
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Row justify="between" align="center" wrap>
                  <Text variant="body" weight="medium" color="var(--ggui-color-onSurface)">
                    {safeForecast[selectedDayIndex].day || 'Selected day'} details
                  </Text>
                  <Badge variant="primary">
                    High {typeof safeForecast[selectedDayIndex].high === 'number' ? safeForecast[selectedDayIndex].high : '--'}° / Low {typeof safeForecast[selectedDayIndex].low === 'number' ? safeForecast[selectedDayIndex].low : '--'}°
                  </Badge>
                </Row>
              </Box>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

