// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean; satisfaction: boolean }>({ name: false, email: false, satisfaction: false });
  const [submissionError, setSubmissionError] = useState<string>('');
  const maxComments = 500;

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !emailValid ? 'Enter a valid email address.' : '';

  const totalSteps = 5;
  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      return name.trim().length > 0 && email.trim().length > 0 && emailValid;
    }
    if (currentStep === 2) {
      return satisfactionOptions.length > 0 && satisfaction !== '';
    }
    if (currentStep === 3) {
      return true;
    }
    if (currentStep === 4) {
      return comments.length <= maxComments;
    }
    return true;
  }, [comments.length, currentStep, emailValid, name, satisfaction, satisfactionOptions.length]);

  const satisfactionOptions = useMemo(() => {
    const safeLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
    return safeLabels.slice(0, 5).map((label, index) => ({
      value: String(index + 1),
      label: ` ${index + 1} - ${label}`
    }));
  }, [props.satisfactionLabels]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (currentStep === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
    }
    if (currentStep === 2) {
      setTouched((prev) => ({ ...prev, satisfaction: true }));
    }
    if (!isStepValid) return;
    setCurrentStep((prev) => (prev < 5 ? prev + 1 : prev));
  }, [currentStep, isStepValid]);

  const goBack = useCallback(() => {
    setCurrentStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    try {
      setSubmissionError('');
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: Number(satisfaction),
        features,
        comments
      });
    } catch (error) {
      setSubmissionError('Unable to submit survey. Please try again.');
    }
  }, [comments, email, features, name, satisfaction, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={4} color="var(--ggui-color-onSurface)">Survey</Heading>
              <Badge variant="primary">Step {currentStep > 4 ? 4 : currentStep} of 4</Badge>
            </Row>
            <Progress value={((currentStep > 4 ? 4 : currentStep) / 4) * 100} max={100} size="md" variant="default" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={5}>Your Details</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => setName(value)}
                required
                error={nameError}
                placeholder="Enter your name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => setEmail(value)}
                required
                error={emailError}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={5}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={(value) => setSatisfaction(value)}
                options={satisfactionOptions}
                error={touched.satisfaction && satisfaction === '' ? 'Please choose a rating to continue.' : undefined}
              />
                {satisfactionOptions.length === 0 && (
                  <Alert variant="warning" title="No rating options available">Please try again when satisfaction labels are available.</Alert>
                )}
              </Stack>
            )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={5}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select all features you are interested in.</Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(Array.isArray(props.featureOptions) ? props.featureOptions : []).length === 0 ? (
                  <Alert variant="info" title="No feature options available">There are currently no feature options to select.</Alert>
                ) : (
                  (Array.isArray(props.featureOptions) ? props.featureOptions : []).map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))
                )}
              </Stack>
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={5}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={(value) => setComments(value.slice(0, maxComments))}
                rows={6}
                maxLength={maxComments}
                showCount
                helperText="Share any additional feedback."
              />
              <Row justify="end">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{comments.length}/{maxComments}</Text>
              </Row>
            </Stack>
          )}

          {currentStep === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={5}>Review Your Answers</Heading>
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                  <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                  <Text>
                    <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                    {satisfaction
                      ? `${satisfaction} - ${(Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [])[Number(satisfaction) - 1] || ''}`
                      : '-'}
                  </Text>
                  <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                  <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() ? comments : 'No comments provided'}</Text>
                </Stack>
              </Box>
            </Stack>
          )}
        </Card>

        <Row justify="between" align="center">
          <Button
            variant="ghost"
            onClick={goBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {currentStep < totalSteps && (
              <Button
                variant="primary"
                disabled={!isStepValid || (currentStep === 2 && satisfaction === '')}
                onClick={goNext}
              >
                Next
              </Button>
            )}
            {currentStep === totalSteps && (
              <Button variant="primary" onClick={handleSubmit}>
                Submit Survey
              </Button>
            )}
          </Row>
        </Row>
        {submissionError && <Alert variant="error" title="Submission Failed">{submissionError}</Alert>}
      </Stack>
    </Container>


  );
}

