interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}


const getCategoryColor = (category?: string): string => {
  const normalized = (category || 'unknown').toLowerCase();
  if (normalized.includes('noble')) return 'var(--ggui-color-primary-100)';
  if (normalized.includes('halogen')) return 'var(--ggui-color-warning-100)';
  if (normalized.includes('alkali metal')) return 'var(--ggui-color-error-100)';
  if (normalized.includes('alkaline earth')) return 'var(--ggui-color-error-50)';
  if (normalized.includes('transition')) return 'var(--ggui-color-info-100)';
  if (normalized.includes('post-transition')) return 'var(--ggui-color-info-50)';
  if (normalized.includes('metalloid')) return 'var(--ggui-color-success-100)';
  if (normalized.includes('nonmetal')) return 'var(--ggui-color-success-50)';
  if (normalized.includes('lanthanide')) return 'var(--ggui-color-primary-50)';
  if (normalized.includes('actinide')) return 'var(--ggui-color-warning-50)';
  return 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const source = Array.isArray(props.elements) ? props.elements : [];
    const q = query.trim().toLowerCase();
    if (!q) return source;
    return source.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [props.elements, query]);

  const selectedElement = useMemo(() => {
    const source = Array.isArray(props.elements) ? props.elements : [];
    if (selectedAtomicNumber === null) return null;
    return source.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [props.elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const source = Array.isArray(props.elements) ? props.elements : [];
    const unique = new Set<string>();
    source.forEach((element) => {
      unique.add(element.category || 'unknown');
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const stillVisible = filteredElements.some((element) => element.atomicNumber === selectedAtomicNumber);
    if (!stillVisible) {
      setSelectedAtomicNumber(null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Interactive Periodic Table</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Explore all elements by category, search by name/symbol, and click an element for details.
          </Text>
        </Stack>

        <Input
          label="Search elements"
          placeholder="Type element name or symbol"
          value={query}
          onChange={setQuery}
          type="search"
        />

        {!Array.isArray(props.elements) || props.elements.length === 0 ? (
          <Alert variant="warning" title="No element data">
            No elements are available to display.
          </Alert>
        ) : (
          <>
            <Card padding="var(--ggui-spacing-4)" shadow="sm">
              <Box
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                  gap: 'var(--ggui-spacing-1)',
                }}
              >
                {filteredElements.length === 0 ? (
                  <Box
                    style={{ gridColumn: '1 / span 18' }}
                    padding="var(--ggui-spacing-4)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
                      No elements match your search.
                    </Text>
                  </Box>
                ) : (
                  filteredElements.map((element, index) => {
                    const atomicNumber = element.atomicNumber ?? index + 1;
                    const isSelected = selectedAtomicNumber === atomicNumber;
                    return (
                      <Card
                        key={`${atomicNumber}-${element.symbol || 'el'}`}
                        as={Clickable}
                        onClick={() => setSelectedAtomicNumber(atomicNumber)}
                        padding="var(--ggui-spacing-2)"
                        shadow="none"
                        radius="md"
                        border
                        hoverStyle={{ opacity: 0.9 }}
                        style={{
                          gridColumn: `${element.col || 1}`,
                          gridRow: `${element.row || 1}`,
                          minHeight: '72px',
                          background: getCategoryColor(element.category),
                          borderColor: isSelected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)',
                          borderWidth: isSelected ? '2px' : '1px',
                          borderStyle: 'solid',
                          position: 'relative',
                        }}
                      >
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurfaceVariant)"
                          is="span"
                          style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                        >
                          {element.atomicNumber ?? '—'}
                        </Text>
                        <Stack align="center" justify="center" style={{ minHeight: '100%' }}>
                          <Text size="xl" weight="bold" align="center">
                            {element.symbol || '—'}
                          </Text>
                        </Stack>
                      </Card>
                    );
                  })
                )}
              </Box>
            </Card>

            <Card padding="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Legend</Heading>
                <Row wrap gap="var(--ggui-spacing-2)">
                  {categories.map((category) => (
                    <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                      <Box
                        style={{ width: '14px', height: '14px' }}
                        background={getCategoryColor(category)}
                        borderRadius="var(--ggui-shape-radius-sm)"
                      />
                      <Text variant="bodySmall">{category}</Text>
                    </Row>
                  ))}
                </Row>
              </Stack>
            </Card>

            <Card padding="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={4}>Element Details</Heading>
                {selectedElement ? (
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text><Text weight="semibold" is="span">Name:</Text> {selectedElement.name || '—'}</Text>
                    <Text><Text weight="semibold" is="span">Symbol:</Text> {selectedElement.symbol || '—'}</Text>
                    <Text><Text weight="semibold" is="span">Atomic Number:</Text> {selectedElement.atomicNumber ?? '—'}</Text>
                    <Text><Text weight="semibold" is="span">Atomic Weight:</Text> {selectedElement.atomicWeight ?? '—'}</Text>
                    <Text><Text weight="semibold" is="span">Category:</Text> {selectedElement.category || '—'}</Text>
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    Select an element in the table to view its details.
                  </Text>
                )}
              </Stack>
            </Card>
          </>
        )}
      </Stack>
    </Container>

  );
}

