  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setChatMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest && (message.latest.text || message.latest.sender || message.latest.timestamp)) {
      setChatMessages((prev) => [...prev, message.latest as StreamMessage]);
