    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canProceed]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    setSubmitted(true);
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [isStep1Valid, isStep2Valid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={1}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)" wrap>
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={!isNameValid && name.length > 0 ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={!isEmailValid && email.length > 0 ? 'Please enter a valid email address.' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" is="label" id="avatar-group-label">Choose your avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {resolvedAvatarOptions.map((option, index) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        onKeyDown={(event: React.KeyboardEvent) => {
                          if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
                            event.preventDefault();
                            const nextIndex = (index + 1) % resolvedAvatarOptions.length;
                            setAvatar(resolvedAvatarOptions[nextIndex]);
                          }
                          if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
                            event.preventDefault();
                            const previousIndex = (index - 1 + resolvedAvatarOptions.length) % resolvedAvatarOptions.length;
                            setAvatar(resolvedAvatarOptions[previousIndex]);
                          }
                        }}
                        role="radio"
                        aria-checked={avatar === option}
                        tabIndex={avatar === option ? 0 : -1}
                        aria-label={`Avatar ${option}`}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text size="2xl">{option}</Text>
                          {avatar === option && <Badge variant="success" size="sm">Selected</Badge>}
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={resolvedRoleOptions.map((item) => ({ value: item, label: item }))}
                  required
                  error={role.trim().length === 0 ? 'Please select a role.' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Current theme: {theme}
                </Text>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please verify your details before completing setup.">
                  You can go back to edit any information.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row align="center" gap="var(--ggui-spacing-3)">
                      <Text size="2xl">{avatar}</Text>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="label">{name || '—'}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{email || '—'}</Text>
                      </Stack>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Row justify="between"><Text variant="bodySmall">Role</Text><Text variant="bodySmall" weight="medium">{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="bodySmall">Email notifications</Text><Text variant="bodySmall" weight="medium">{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="bodySmall">Theme</Text><Text variant="bodySmall" weight="medium">{theme}</Text></Row>
                  </Stack>
                </Card>
                {submitted && <Alert variant="success" title="Setup completed">Your onboarding data has been submitted.</Alert>}
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={handleBack} disabled={step === 1}>
            Go Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid || !isStep2Valid}>
                Complete Setup
              </Button>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
